const apiResponse = $input.all()[0].json;
const quantity = apiResponse.items.length;
const currentVacancies = apiResponse.items;

const result = {
  quantity: quantity,
  raw_items: currentVacancies
};

return result;

const inputs = $input.all();
let text = '';

if (inputs.length > 0) {
  const firstInput = inputs[0];
  text = firstInput.json.output;
}

const lines = text.split('\n');
const result = [];

if (lines.length > 0) {
  result.push('📊 ' + lines[0]);

  for (let i = 1; i < lines.length; i++) {
    const line = lines[i].trim();
    if (line) {
      let emoji = '💡';
      if (line.includes('Excel') || line.includes('SQL') || line.includes('BPMN') || line.includes('ПО')) emoji = '💻';
      else if (line.includes('моделирование') || line.includes('анализ')) emoji = '📈';
      else if (line.includes('процесс')) emoji = '🔍';
      else if (line.includes('переговор')) emoji = '🤝';
      else if (line.includes('1С')) emoji = '🏢';
      else if (line.includes('оптимизац')) emoji = '⚙️';
      result.push(emoji + ' ' + line);
    }
  }
}

return [{
  json: {
    result: result.join('\n')
  }
}];
